import math
import os
import random
import re
import sys
from itertools import permutations

if __name__ == '__main__':
    a = list(map(int, input().rstrip().split()))
    n, m = a[0], a[1]
    if m == n:
        print(0)
    elif m % n != 0:
        print(-1)
    else:
        d = m // n
        count = 0
        for factor in [2, 3]:
            while d % factor == 0:
                count += 1
                d = d // factor
        if d == 1:
            print(count)
        else:
            print(-1)
